class Solution {
    int[] w;

    public Solution(int[] w) {
        this.w = w.clone();
    }

    public int pickIndex() {
        int sum = calculateSum();
        return randomIndex(sum);
    }

    private int randomIndex(int sum) {
        Random rand = new Random();
        int index = rand.nextInt(sum);
        return index;
    }

    private int calculateSum() {
        int sum = 1;
        for (int w : w) {
            sum += w;
        }
        return sum;
    }
}
```

